"""matplotlib.texmanager — TeX rendering stubs."""

class TexManager:
    @staticmethod
    def get_rgba_preview(tex, fontsize=12, dpi=150, rgb=(0, 0, 0)):
        import numpy as np
        return np.zeros((10, 10, 4), dtype=np.uint8)

    @staticmethod
    def get_text_width_height_descent(tex, fontsize, renderer=None):
        return (0, 0, 0)

    @staticmethod
    def get_grey(tex, fontsize=12, dpi=150):
        import numpy as np
        return np.zeros((10, 10), dtype=np.uint8)
